{
  "name": "SubtitlePro AI Studio",
  "description": "An elite social media subtitle engineer for generating phonetically accurate, semantically chunked captions for Reels, TikTok, and Shorts with specialized support for Arabic formatting.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface SubtitleChunk {
  text: string;
  start: number;
  end: number;
}

export enum AppStatus {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  PROCESSING = 'PROCESSING',
  EDITING = 'EDITING',
  ERROR = 'ERROR'
}

export interface ProcessingOptions {
  wordCount: number;
  language?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SubtitleChunk, ProcessingOptions } from "../types";

const SYSTEM_INSTRUCTION = `You are an elite Social Media Subtitle Engineer and Video Editor. Your goal is to transcribe audio with 100% phonetic precision and segment it into perfectly timed SRT chunks.

CORE OPERATIONAL RULES:
1. PHONETIC ACCURACY: Transcribe exactly what is spoken. Maintain original dialects, slang, and fillers (e.g., Egyptian or Gulf Arabic). Do not correct grammar or convert to formal language.
2. SEMANTIC CHUNKING: Break sentences into small, readable units that feel natural for Reels/TikTok. Group words that belong together logically.
3. LINE LENGTH CONSTRAINT: Strictly adhere to the target word count provided. Prioritize visual balance for mobile screens.
4. ARABIC FORMATTING (THE "AL-" RULE): For the Arabic definite article "ال" followed by a number or an English word, you MUST use the "الـ" format (e.g., الـiPhone, الـ20, الـMarketing).
5. TIMESTAMP PRECISION: Ensure 'start' and 'end' times are accurate to the audio fingerprint.
6. OUTPUT FORMAT: Respond ONLY with a valid JSON array of objects.
Structure: [{"text": "string", "start": float, "end": float}]`;

export const transcribeAudio = async (
  base64Audio: string, 
  mimeType: string,
  options: ProcessingOptions
): Promise<SubtitleChunk[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Transcribe this audio. Target word count per segment: ${options.wordCount}. Language: ${options.language || 'Auto-detect'}. Output JSON only.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { data: base64Audio, mimeType } },
          { text: prompt }
        ]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              text: { type: Type.STRING },
              start: { type: Type.NUMBER },
              end: { type: Type.NUMBER },
            },
            required: ["text", "start", "end"],
          },
        },
      }
    });

    const text = response.text;
    if (!text) throw new Error("No transcription received from Gemini.");

    return JSON.parse(text) as SubtitleChunk[];
  } catch (error) {
    console.error("Transcription error:", error);
    throw error;
  }
};

import { SubtitleChunk } from "../types";

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve(base64String);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const formatTimestamp = (seconds: number): string => {
  const date = new Date(0);
  date.setSeconds(seconds);
  const timeString = date.toISOString().substr(11, 8);
  const ms = Math.floor((seconds % 1) * 1000).toString().padStart(3, '0');
  return `${timeString},${ms}`;
};

export const generateSRT = (chunks: SubtitleChunk[]): string => {
  return chunks
    .map((chunk, index) => {
      return `${index + 1}\n${formatTimestamp(chunk.start)} --> ${formatTimestamp(chunk.end)}\n${chunk.text}\n`;
    })
    .join('\n');
};

export const downloadFile = (content: string, filename: string, contentType: string) => {
  const blob = new Blob([content], { type: contentType });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = filename;
  link.click();
  URL.revokeObjectURL(url);
};

