import React from 'react';
import { SubtitleChunk } from '../types';

interface SubtitleListProps {
  chunks: SubtitleChunk[];
  onUpdateChunk: (index: number, updated: Partial<SubtitleChunk>) => void;
  onRemoveChunk: (index: number) => void;
  currentTime: number;
}

const SubtitleList: React.FC<SubtitleListProps> = ({ chunks, onUpdateChunk, onRemoveChunk, currentTime }) => {
  return (
    <div className="space-y-3 pb-24">
      {chunks.map((chunk, index) => {
        const isActive = currentTime >= chunk.start && currentTime <= chunk.end;

        return (
          <div 
            key={index} 
            className={`group p-4 rounded-xl border transition-all duration-300 ${
              isActive 
                ? 'bg-indigo-600/10 border-indigo-500/50 shadow-lg shadow-indigo-500/5' 
                : 'bg-slate-800/50 border-slate-700 hover:border-slate-500'
            }`}
          >
            <div className="flex items-start justify-between mb-2">
              <div className="flex space-x-3 items-center">
                <span className="text-xs font-mono text-slate-500 bg-slate-900 px-2 py-1 rounded">
                  {chunk.start.toFixed(2)}s → {chunk.end.toFixed(2)}s
                </span>
                {isActive && (
                  <span className="flex h-2 w-2 relative">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-indigo-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-2 w-2 bg-indigo-500"></span>
                  </span>
                )}
              </div>
              <button 
                onClick={() => onRemoveChunk(index)}
                className="opacity-0 group-hover:opacity-100 text-slate-500 hover:text-red-400 transition-opacity"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </button>
            </div>
            <textarea
              value={chunk.text}
              onChange={(e) => onUpdateChunk(index, { text: e.target.value })}
              className={`w-full bg-transparent border-none focus:ring-0 text-lg leading-relaxed resize-none p-0 overflow-hidden ${
                chunk.text.match(/[\u0600-\u06FF]/) ? 'font-arabic text-right' : 'font-medium'
              }`}
              rows={Math.ceil(chunk.text.length / 30) || 1}
              dir="auto"
            />
          </div>
        );
      })}
    </div>
  );
};

export default SubtitleList;

import React, { useState, useRef, useEffect } from 'react';
import { SubtitleChunk, AppStatus, ProcessingOptions } from '../types';
import SubtitleList from './SubtitleList';
import { transcribeAudio } from '../services/geminiService';
import { fileToBase64, generateSRT, downloadFile } from '../utils/helpers';

interface StudioProps {
  initialFile: File | null;
  onReset: () => void;
}

const Studio: React.FC<StudioProps> = ({ initialFile, onReset }) => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [chunks, setChunks] = useState<SubtitleChunk[]>([]);
  const [options, setOptions] = useState<ProcessingOptions>({ wordCount: 3 });
  const [currentTime, setCurrentTime] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);
  const [mediaUrl, setMediaUrl] = useState<string | null>(null);
  const [isMediaVideo, setIsMediaVideo] = useState(false);

  useEffect(() => {
    if (initialFile) {
      const url = URL.createObjectURL(initialFile);
      setMediaUrl(url);
      setIsMediaVideo(initialFile.type.startsWith('video/'));
      handleProcessFile(initialFile);
    }
    return () => {
      if (mediaUrl) URL.revokeObjectURL(mediaUrl);
    };
  }, [initialFile]);

  const handleProcessFile = async (file: File) => {
    try {
      setStatus(AppStatus.PROCESSING);
      setError(null);
      const base64 = await fileToBase64(file);
      const result = await transcribeAudio(base64, file.type, options);
      setChunks(result);
      setStatus(AppStatus.EDITING);
    } catch (err: any) {
      setError(err.message || "Failed to process audio.");
      setStatus(AppStatus.ERROR);
    }
  };

  const handleTimeUpdate = (e: React.SyntheticEvent<HTMLMediaElement>) => {
    setCurrentTime(e.currentTarget.currentTime);
  };

  const updateChunk = (index: number, updated: Partial<SubtitleChunk>) => {
    const newChunks = [...chunks];
    newChunks[index] = { ...newChunks[index], ...updated };
    setChunks(newChunks);
  };

  const removeChunk = (index: number) => {
    setChunks(chunks.filter((_, i) => i !== index));
  };

  const activeChunk = chunks.find(c => currentTime >= c.start && currentTime <= c.end);

  const exportSRT = () => {
    const srt = generateSRT(chunks);
    downloadFile(srt, "subtitles.srt", "text/plain");
  };

  const exportJSON = () => {
    downloadFile(JSON.stringify(chunks, null, 2), "subtitles.json", "application/json");
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8 h-full flex flex-col md:flex-row gap-8">
      {/* Left Column: Preview & Controls */}
      <div className="w-full md:w-1/2 flex flex-col space-y-6">
        <div className="relative aspect-video bg-black rounded-2xl overflow-hidden shadow-2xl border border-slate-800">
          {mediaUrl && isMediaVideo ? (
            <video 
              ref={videoRef}
              src={mediaUrl} 
              onTimeUpdate={handleTimeUpdate}
              controls 
              className="w-full h-full object-contain"
            />
          ) : mediaUrl ? (
            <div className="w-full h-full flex flex-col items-center justify-center bg-slate-900">
                <div className="w-32 h-32 bg-indigo-500/20 rounded-full flex items-center justify-center animate-pulse mb-4">
                  <svg className="w-12 h-12 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" />
                  </svg>
                </div>
                <audio ref={audioRef} src={mediaUrl} onTimeUpdate={handleTimeUpdate} controls className="w-2/3" />
            </div>
          ) : null}

          {/* Overlay Subtitles (Safe Area Preview) */}
          <div className="absolute inset-x-0 bottom-12 flex justify-center pointer-events-none">
            {activeChunk && (
              <div className="bg-black/80 backdrop-blur-sm px-4 py-2 rounded-lg border border-white/10 max-w-[80%]">
                <p className={`text-center text-white text-xl shadow-sm ${activeChunk.text.match(/[\u0600-\u06FF]/) ? 'font-arabic' : 'font-bold'}`}>
                  {activeChunk.text}
                </p>
              </div>
            )}
          </div>
        </div>

        <div className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800">
          <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4">Processing Options</h3>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs text-slate-500 mb-2">Word Count Limit</label>
              <select 
                value={options.wordCount}
                onChange={(e) => setOptions({...options, wordCount: parseInt(e.target.value)})}
                className="w-full bg-slate-800 border-slate-700 rounded-lg text-sm px-3 py-2"
              >
                <option value={2}>2 Words (Snappy)</option>
                <option value={3}>3 Words (Standard)</option>
                <option value={4}>4 Words (Readable)</option>
              </select>
            </div>
            <div className="flex items-end">
              <button 
                onClick={() => initialFile && handleProcessFile(initialFile)}
                disabled={status === AppStatus.PROCESSING}
                className="w-full bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 text-white font-bold py-2 px-4 rounded-lg text-sm transition-all"
              >
                {status === AppStatus.PROCESSING ? 'Retranscribing...' : 'Regenerate'}
              </button>
            </div>
          </div>
        </div>

        <div className="flex gap-4">
          <button 
            onClick={exportSRT}
            className="flex-1 bg-emerald-600 hover:bg-emerald-500 text-white py-3 rounded-xl font-bold flex items-center justify-center space-x-2 shadow-lg shadow-emerald-900/20"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" strokeLinecap="round" strokeLinejoin="round" strokeWidth={2}/></svg>
            <span>Export SRT</span>
          </button>
          <button 
            onClick={onReset}
            className="px-6 border border-slate-700 hover:bg-slate-800 text-slate-400 py-3 rounded-xl font-bold transition-all"
          >
            New Project
          </button>
        </div>
      </div>

      {/* Right Column: Editor */}
      <div className="w-full md:w-1/2 flex flex-col h-[70vh] md:h-auto">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-bold flex items-center">
            <span className="w-2 h-2 bg-indigo-500 rounded-full mr-2"></span>
            Subtitle Timeline
          </h2>
          <div className="flex items-center space-x-2">
             <span className="text-xs text-slate-500">{chunks.length} Segments</span>
             <button onClick={exportJSON} className="text-xs text-indigo-400 hover:underline">Export JSON</button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
          {status === AppStatus.PROCESSING && (
            <div className="flex flex-col items-center justify-center h-full space-y-4">
              <div className="relative w-20 h-20">
                <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
                <div className="absolute inset-0 border-4 border-t-indigo-500 rounded-full animate-spin"></div>
              </div>
              <div className="text-center">
                <p className="text-indigo-400 font-bold animate-pulse">Gemini 3 Flash Thinking...</p>
                <p className="text-slate-500 text-sm mt-1">Transcribing with phonetic precision</p>
              </div>
            </div>
          )}

          {error && (
            <div className="bg-red-900/20 border border-red-500/50 p-6 rounded-2xl text-center">
               <p className="text-red-400 font-medium mb-4">{error}</p>
               <button onClick={() => initialFile && handleProcessFile(initialFile)} className="bg-red-500 hover:bg-red-400 text-white px-4 py-2 rounded-lg text-sm font-bold">Try Again</button>
            </div>
          )}

          {status === AppStatus.EDITING && (
            <SubtitleList 
              chunks={chunks} 
              onUpdateChunk={updateChunk} 
              onRemoveChunk={removeChunk} 
              currentTime={currentTime}
            />
          )}
        </div>
      </div>
    </div>
  );
};

export default Studio;

import React, { useCallback, useState } from 'react';

interface UploadZoneProps {
  onFileSelect: (file: File) => void;
}

const UploadZone: React.FC<UploadZoneProps> = ({ onFileSelect }) => {
  const [isDragging, setIsDragging] = useState(false);

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setIsDragging(true);
    } else if (e.type === 'dragleave') {
      setIsDragging(false);
    }
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);

    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      onFileSelect(e.dataTransfer.files[0]);
    }
  }, [onFileSelect]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onFileSelect(e.target.files[0]);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-6 py-12 md:py-24 text-center">
      <div className="mb-12">
        <span className="inline-block px-3 py-1 bg-indigo-500/10 text-indigo-400 text-xs font-bold rounded-full mb-4 border border-indigo-500/20">
          POWERED BY GEMINI 3 FLASH
        </span>
        <h2 className="text-4xl md:text-6xl font-extrabold text-white mb-6 tracking-tight">
          Next-Gen <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-purple-400">Social Captions</span>
        </h2>
        <p className="text-lg text-slate-400 max-w-2xl mx-auto">
          Elite transcription with 100% phonetic precision. Specialized semantic chunking for TikTok, Reels, and Shorts.
        </p>
      </div>

      <div
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
        className={`relative group cursor-pointer border-2 border-dashed rounded-3xl p-12 transition-all duration-300 ${
          isDragging 
            ? 'border-indigo-500 bg-indigo-500/5' 
            : 'border-slate-800 hover:border-slate-600 bg-slate-900/50 hover:bg-slate-800/80'
        }`}
      >
        <input
          type="file"
          id="file-upload"
          className="hidden"
          accept="audio/*,video/*"
          onChange={handleFileChange}
        />
        <label htmlFor="file-upload" className="cursor-pointer flex flex-col items-center">
          <div className="w-16 h-16 bg-slate-800 rounded-2xl flex items-center justify-center mb-6 shadow-inner transition-transform group-hover:scale-110">
            <svg className="w-8 h-8 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
            </svg>
          </div>
          <p className="text-xl font-bold text-white mb-2">Drop your media here</p>
          <p className="text-slate-500 text-sm">MP4, MOV, MP3, WAV (up to 50MB)</p>
          <div className="mt-8 bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-xl font-bold transition-all shadow-lg shadow-indigo-600/20">
            Select File
          </div>
        </label>
      </div>

      <div className="mt-16 grid grid-cols-1 md:grid-cols-3 gap-8">
        {[
          { icon: '🎯', title: 'Phonetic Precision', desc: 'Maintains dialects, slang, and fillers exactly as spoken.' },
          { icon: '✂️', title: 'Semantic Chunking', desc: 'Auto-segments into snappy 2-4 word blocks for visual flow.' },
          { icon: '🌍', title: 'Arabic Pro-Mode', desc: 'Correct "الـ" formatting for English and number mix-ins.' }
        ].map((feature, i) => (
          <div key={i} className="bg-slate-900/40 p-6 rounded-2xl border border-slate-800 text-left">
            <div className="text-2xl mb-3">{feature.icon}</div>
            <h4 className="text-white font-bold mb-2">{feature.title}</h4>
            <p className="text-slate-500 text-sm">{feature.desc}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default UploadZone;

