      {/* Settings Before Upload */}
      <div className="mb-8 max-w-md mx-auto bg-slate-900/80 border border-slate-800 p-5 rounded-2xl flex flex-col items-center">
        <label className="text-sm font-bold text-slate-300 mb-3 font-arabic">إعدادات الكابشن (قبل الرفع)</label>
