import { GoogleGenAI, Type } from "@google/genai";
import { SubtitleChunk, ProcessingOptions } from "../types";

const SYSTEM_INSTRUCTION = `You are an elite Social Media Subtitle Engineer and Video Editor. Your goal is to transcribe audio with 100% phonetic precision and segment it into perfectly timed SRT chunks.

CORE OPERATIONAL RULES:
1. PHONETIC ACCURACY: Transcribe exactly what is spoken. Maintain original dialects, slang, and fillers (e.g., Egyptian or Gulf Arabic). Do not correct grammar or convert to formal language.
2. SEMANTIC CHUNKING: Break sentences into small, readable units that feel natural for Reels/TikTok. Group words that belong together logically.
3. LINE LENGTH CONSTRAINT: Strictly adhere to the target word count provided. Prioritize visual balance for mobile screens.
4. ARABIC FORMATTING (THE "AL-" RULE): If English characters are being used and are preceded by the Arabic definite article "ال", you MUST use the "الـ" format (e.g., الـiPhone, الـ20, الـMarketing).
5. TIMESTAMP PRECISION: Ensure 'start' and 'end' times are accurate to the audio fingerprint.
6. ENGLISH WORD HANDLING:
   - If user requests 'english' format: Write English terms/words using English script (e.g., 'Discount', 'For free', 'Marketing').
   - If user requests 'phonetic_arabic' format: Transcribe English terms/words phonetically into Arabic script (e.g., 'ديسكونت', 'فور فري', 'ماركتنج').
7. OUTPUT FORMAT: Respond ONLY with a valid JSON array of objects.
Structure: [{"text": "string", "start": float, "end": float}]`;

export const transcribeAudio = async (
  base64Audio: string, 
  mimeType: string,
  options: ProcessingOptions
): Promise<SubtitleChunk[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Transcribe this audio. 
  Target word count per segment: ${options.wordCount}. 
  English Word Format Preference: ${options.englishFormat}.
  Language: ${options.language || 'Auto-detect'}. 
  Output JSON only.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { data: base64Audio, mimeType } },
          { text: prompt }
        ]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              text: { type: Type.STRING },
              start: { type: Type.NUMBER },
              end: { type: Type.NUMBER },
            },
            required: ["text", "start", "end"],
          },
        },
      }
    });

    const text = response.text;
    if (!text) throw new Error("No transcription received from Gemini.");

    return JSON.parse(text) as SubtitleChunk[];
  } catch (error) {
    console.error("Transcription error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { SubtitleChunk, AppStatus, ProcessingOptions, EnglishFormat } from '../types';
import SubtitleList from './SubtitleList';
import { transcribeAudio } from '../services/geminiService';
import { fileToBase64, generateSRT, downloadFile } from '../utils/helpers';

interface StudioProps {
  initialFile: File | null;
  onReset: () => void;
  initialWordCount: number;
  initialEnglishFormat: EnglishFormat;
}

const Studio: React.FC<StudioProps> = ({ initialFile, onReset, initialWordCount, initialEnglishFormat }) => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [chunks, setChunks] = useState<SubtitleChunk[]>([]);
  const [options, setOptions] = useState<ProcessingOptions>({ 
    wordCount: initialWordCount, 
    englishFormat: initialEnglishFormat 
  });
  const [currentTime, setCurrentTime] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);
  const [mediaUrl, setMediaUrl] = useState<string | null>(null);
  const [isMediaVideo, setIsMediaVideo] = useState(false);

  useEffect(() => {
    if (initialFile) {
      const url = URL.createObjectURL(initialFile);
      setMediaUrl(url);
      setIsMediaVideo(initialFile.type.startsWith('video/'));
      handleProcessFile(initialFile);
    }
    return () => {
      if (mediaUrl) URL.revokeObjectURL(mediaUrl);
    };
  }, [initialFile]);

  const handleProcessFile = async (file: File) => {
    try {
      setStatus(AppStatus.PROCESSING);
      setError(null);
      const base64 = await fileToBase64(file);
      const result = await transcribeAudio(base64, file.type, options);
      setChunks(result);
      setStatus(AppStatus.EDITING);
    } catch (err: any) {
      setError(err.message || "Failed to process audio.");
      setStatus(AppStatus.ERROR);
    }
  };

  const handleTimeUpdate = (e: React.SyntheticEvent<HTMLMediaElement>) => {
    setCurrentTime(e.currentTarget.currentTime);
  };

  const updateChunk = (index: number, updated: Partial<SubtitleChunk>) => {
    const newChunks = [...chunks];
    newChunks[index] = { ...newChunks[index], ...updated };
    setChunks(newChunks);
  };

  const removeChunk = (index: number) => {
    setChunks(chunks.filter((_, i) => i !== index));
  };

  const activeChunk = chunks.find(c => currentTime >= c.start && currentTime <= c.end);

  const exportSRT = () => {
    const srt = generateSRT(chunks);
    downloadFile(srt, "subtitles.srt", "text/plain");
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8 h-full flex flex-col md:flex-row gap-8 overflow-hidden">
      {/* Left Column: Preview (Sticky) */}
      <div className="w-full md:w-5/12 lg:w-4/12 flex flex-col space-y-6">
        <div className="relative aspect-[9/16] bg-black rounded-2xl overflow-hidden shadow-2xl border border-slate-800 max-h-[60vh] md:max-h-none mx-auto w-full max-w-[320px] md:max-w-none">
          {mediaUrl && isMediaVideo ? (
            <video 
              ref={videoRef}
              src={mediaUrl} 
              onTimeUpdate={handleTimeUpdate}
              controls 
              className="w-full h-full object-contain"
            />
          ) : mediaUrl ? (
            <div className="w-full h-full flex flex-col items-center justify-center bg-slate-900">
                <div className="w-24 h-24 bg-indigo-500/20 rounded-full flex items-center justify-center animate-pulse mb-4">
                  <svg className="w-10 h-10 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" />
                  </svg>
                </div>
                <audio ref={audioRef} src={mediaUrl} onTimeUpdate={handleTimeUpdate} controls className="w-4/5" />
            </div>
          ) : null}

          {/* Subtitle Overlay Preview */}
          <div className="absolute inset-x-0 bottom-20 flex justify-center pointer-events-none px-4">
            {activeChunk && (
              <div className="bg-indigo-600 text-white px-3 py-1.5 rounded shadow-xl text-center border border-indigo-400/50">
                <p className={`text-sm md:text-base font-bold ${activeChunk.text.match(/[\u0600-\u06FF]/) ? 'font-arabic' : ''}`}>
                  {activeChunk.text}
                </p>
              </div>
            )}
          </div>
        </div>

        <div className="flex flex-col gap-3">
          <button 
            onClick={exportSRT}
            className="w-full bg-indigo-600 hover:bg-indigo-500 text-white py-3 rounded-xl font-bold flex items-center justify-center space-x-2 shadow-lg shadow-indigo-900/20 transition-all font-arabic"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" strokeLinecap="round" strokeLinejoin="round" strokeWidth={2}/></svg>
            <span>تحميل ملف SRT</span>
          </button>
          <button 
            onClick={onReset}
            className="w-full border border-slate-700 hover:bg-slate-800 text-slate-400 py-3 rounded-xl font-bold transition-all font-arabic text-sm"
          >
            مشروع جديد
          </button>
        </div>
      </div>

      {/* Right Column: Scrollable Editor Area */}
      <div className="w-full md:w-7/12 lg:w-8/12 flex flex-col">
        <div className="bg-slate-900/80 border border-slate-800 rounded-2xl flex flex-col h-[600px] shadow-xl">
          <div className="px-6 py-4 border-b border-slate-800 flex items-center justify-between">
            <h2 className="text-lg font-bold flex items-center font-arabic">
              <span className="w-2 h-2 bg-indigo-500 rounded-full mr-2"></span>
              قائمة الكابشنز المستخرجة
            </h2>
            <div className="flex flex-col items-end space-y-1">
               <div className="flex items-center space-x-2">
                 <span className="text-[10px] bg-indigo-500/20 px-2 py-0.5 rounded text-indigo-400 font-mono uppercase">{options.wordCount} WPL</span>
                 <span className="text-[10px] bg-indigo-500/20 px-2 py-0.5 rounded text-indigo-400 font-mono uppercase">{options.englishFormat === 'english' ? 'EN Script' : 'AR Phonetic'}</span>
               </div>
               <span className="text-xs text-slate-500 font-arabic">{chunks.length} جزء</span>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
            {status === AppStatus.PROCESSING && (
              <div className="flex flex-col items-center justify-center h-full space-y-4">
                <div className="w-12 h-12 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin"></div>
                <div className="text-center">
                  <p className="text-indigo-400 font-bold animate-pulse font-arabic">جاري معالجة الصوت...</p>
                  <p className="text-slate-500 text-sm mt-1 font-arabic">الذكاء الاصطناعي يقوم بالتقسيم الصوتي الآن</p>
                </div>
              </div>
            )}

            {error && (
              <div className="h-full flex flex-col items-center justify-center p-6 text-center">
                 <p className="text-red-400 font-medium mb-4 font-arabic">{error}</p>
                 <button onClick={() => initialFile && handleProcessFile(initialFile)} className="bg-red-500 hover:bg-red-400 text-white px-6 py-2 rounded-lg text-sm font-bold font-arabic">إعادة المحاولة</button>
              </div>
            )}

            {status === AppStatus.EDITING && (
              <SubtitleList 
                chunks={chunks} 
                onUpdateChunk={updateChunk} 
                onRemoveChunk={removeChunk} 
                currentTime={currentTime}
              />
            )}

            {status === AppStatus.IDLE && !chunks.length && !error && (
               <div className="h-full flex flex-col items-center justify-center text-slate-600">
                  <p className="font-arabic">بانتظار معالجة الملف...</p>
               </div>
            )}
          </div>
        </div>

        <div className="mt-4 p-4 bg-indigo-600/5 border border-indigo-500/10 rounded-xl">
          <p className="text-xs text-slate-400 font-arabic leading-relaxed">
            <span className="text-indigo-400 font-bold">نصيحة:</span> يمكنك التعديل مباشرة على أي نص في القائمة أعلاه، وسيتم تحديثه في الوقت الفعلي في العرض المباشر. يتم تطبيق اختيارك لنمط الكلمات الإنجليزية (${options.englishFormat === 'english' ? 'English' : 'عربي صوتي'}) على كامل النص.
          </p>
        </div>
      </div>
    </div>
  );
};

export default Studio;

