interface StudioProps {
  initialFile: File | null;
  onReset: () => void;
  options: ProcessingOptions;
  uiLang: UILanguage;
}

const Studio: React.FC<StudioProps> = ({ initialFile, onReset, options, uiLang }) => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [chunks, setChunks] = useState<SubtitleChunk[]>([]);
  const [currentTime, setCurrentTime] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);
  const [mediaUrl, setMediaUrl] = useState<string | null>(null);
  const [isMediaVideo, setIsMediaVideo] = useState(false);

  const isArUI = uiLang === 'ar';
  const t = {
    loading: isArUI ? 'جاري التحليل الذكي...' : 'AI Analyzing...',
    loadingSub: isArUI ? 'يتم استخراج النص وتزامن الوقت بدقة' : 'Extracting text and syncing timestamps...',
    title: isArUI ? 'قائمة الكابشنز' : 'Caption Timeline',
    segments: isArUI ? 'جزء' : 'Segments',
    downloadBtn: isArUI ? 'تحميل ملف SRT' : 'Download SRT',
    newProject: isArUI ? 'مشروع جديد' : 'New Project',
    tip: isArUI ? 'يمكنك التعديل يدوياً على أي نص في القائمة أعلاه.' : 'You can manually edit any text in the list above.',
    retry: isArUI ? 'إعادة المحاولة' : 'Retry',
  };

  useEffect(() => {
    if (initialFile) {
      const url = URL.createObjectURL(initialFile);
      setMediaUrl(url);
      setIsMediaVideo(initialFile.type.startsWith('video/'));
      handleProcessFile(initialFile);
    }
    return () => { if (mediaUrl) URL.revokeObjectURL(mediaUrl); };
  }, [initialFile]);

  const handleProcessFile = async (file: File) => {
    try {
      setStatus(AppStatus.PROCESSING);
      setError(null);
      const base64 = await fileToBase64(file);
      const result = await transcribeAudio(base64, file.type, options);
      setChunks(result);
      setStatus(AppStatus.EDITING);
    } catch (err: any) {
      setError(err.message || "Failed.");
      setStatus(AppStatus.ERROR);
    }
  };

  const handleTimeUpdate = (e: React.SyntheticEvent<HTMLMediaElement>) => setCurrentTime(e.currentTarget.currentTime);

  const activeChunk = chunks.find(c => currentTime >= c.start && currentTime <= c.end);

  return (
    <div className={`max-w-7xl mx-auto px-4 py-8 h-full flex flex-col md:flex-row gap-10 overflow-hidden ${isArUI ? 'font-arabic' : ''}`}>
