          {mediaUrl && (isMediaVideo ? (
            <video ref={videoRef} src={mediaUrl} onTimeUpdate={handleTimeUpdate} controls className="w-full h-full object-contain" />
          ) : (
            <div className="w-full h-full flex flex-col items-center justify-center bg-slate-900">
                <div className="w-24 h-24 bg-indigo-500/10 rounded-full flex items-center justify-center animate-pulse mb-6 ring-1 ring-indigo-500/20">
                  <svg className="w-10 h-10 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" strokeWidth={2}/></svg>
                </div>
                <audio ref={audioRef} src={mediaUrl} onTimeUpdate={handleTimeUpdate} controls className="w-4/5" />
            </div>
          ))}

          <div className="absolute inset-x-0 bottom-24 flex justify-center pointer-events-none px-6">
            {activeChunk && (
              <div className="bg-indigo-600/95 text-white px-4 py-2 rounded-xl shadow-2xl text-center border border-white/20 backdrop-blur-md scale-110">
                <p className={`text-sm md:text-base font-black ${activeChunk.text.match(/[\u0600-\u06FF]/) ? 'font-arabic' : ''}`}>
                  {activeChunk.text}
                </p>
              </div>
            )}
          </div>
        </div>

        <div className="flex flex-col gap-3">
          <button 
            onClick={() => downloadFile(generateSRT(chunks), "subtitles.srt", "text/plain")}
            className="w-full bg-indigo-600 hover:bg-indigo-500 text-white py-4 rounded-2xl font-black flex items-center justify-center space-x-2 shadow-xl shadow-indigo-600/20 transition-all hover:scale-[1.02]"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" strokeWidth={2}/></svg>
            <span>{t.downloadBtn}</span>
          </button>
          <button onClick={onReset} className="w-full text-slate-500 hover:text-white py-2 font-bold text-xs transition-all tracking-widest uppercase">
            {t.newProject}
          </button>
        </div>
      </div>

      {/* Editor Column */}
      <div className="w-full md:w-7/12 lg:w-8/12 flex flex-col">
        <div className="glass rounded-[2rem] flex flex-col h-[650px] shadow-2xl overflow-hidden">
          <div className="px-8 py-5 border-b border-white/5 flex items-center justify-between">
            <h2 className="text-lg font-black flex items-center">
              <span className="w-2 h-2 bg-indigo-500 rounded-full mr-3 animate-pulse"></span>
              {t.title}
            </h2>
            <div className="flex items-center space-x-2">
               <span className="text-[10px] bg-indigo-500/10 border border-indigo-500/20 px-3 py-1 rounded-full text-indigo-400 font-black uppercase tracking-widest">{chunks.length} {t.segments}</span>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-6 scrollbar-hide">
            {status === AppStatus.PROCESSING && (
              <div className="flex flex-col items-center justify-center h-full space-y-6">
                <div className="w-16 h-16 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin"></div>
                <div className="text-center">
                  <p className="text-white text-xl font-black animate-pulse">{t.loading}</p>
                  <p className="text-slate-500 text-sm mt-2">{t.loadingSub}</p>
                </div>
              </div>
            )}

            {error && (
              <div className="h-full flex flex-col items-center justify-center p-8 text-center">
                 <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mb-6 border border-red-500/20 text-red-400">
                   <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth={2}/></svg>
                 </div>
                 <p className="text-white font-black text-lg mb-6">{error}</p>
