              </div>
            )}

            {status === AppStatus.EDITING && (
              <SubtitleList 
                chunks={chunks} 
                onUpdateChunk={(i, u) => { const n = [...chunks]; n[i] = {...n[i], ...u}; setChunks(n); }} 
                onRemoveChunk={(i) => setChunks(chunks.filter((_, idx) => idx !== i))} 
                currentTime={currentTime}
              />
            )}
          </div>
        </div>

        <div className="mt-6 p-5 glass rounded-2xl border-indigo-500/10">
          <p className="text-xs text-slate-400 leading-relaxed font-bold">
            <span className="text-indigo-400 uppercase tracking-widest mr-2">Pro Tip:</span> {t.tip}
          </p>
        </div>
      </div>
    </div>
  );
};

