export interface SubtitleChunk {
  text: string;
  start: number;
  end: number;
  label?: 'hook' | 'cta' | 'important' | 'value' | 'question' | 'humor';
}

export interface SocialMediaKit {
  caption: string;
  hashtags: string[];
  summary: string;
  hooks: string[];
}

export enum AppStatus {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  PROCESSING = 'PROCESSING',
  EDITING = 'EDITING',
  ERROR = 'ERROR'
}

export type EnglishFormat = 'english' | 'phonetic_arabic';
export type UILanguage = 'ar' | 'en';

export interface ProcessingOptions {
  wordCount: number;
  targetLanguage: string;
  dialect?: string;
  englishFormat: EnglishFormat;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SubtitleChunk, ProcessingOptions, SocialMediaKit } from "../types";

const SYSTEM_INSTRUCTION = `You are an elite Social Media Content Engineer (subfy). Your goal is to transcribe audio with 100% phonetic precision, segment it into SRT chunks, and provide high-level social media analysis.

CORE OPERATIONAL RULES:
1. PHONETIC ACCURACY: Transcribe exactly what is spoken. For Arabic, use the specific dialect provided.
2. SEMANTIC CHUNKING: Break sentences into snappy, readable units.
3. LABELING (NEW): For each chunk, identify if it is a 'hook' (attention-grabbing start), 'cta' (call to action), 'important' (key info), 'value' (benefits), 'question', or 'humor'. If none, leave empty.
4. SOCIAL MEDIA KIT: Generate a professional social media caption optimized for SEO, including trending hashtags and a summary of hooks.
5. ARABIC FORMATTING: Use "الـ" for English terms (e.g., الـiPhone).
6. OUTPUT FORMAT: Respond ONLY with a valid JSON object containing 'chunks' (array) and 'kit' (object).
Structure: {
  "chunks": [{"text": "string", "start": float, "end": float, "label": "string"}],
  "kit": {
    "caption": "string",
    "hashtags": ["string"],
    "summary": "string",
    "hooks": ["string"]
  }
}`;

export const transcribeAudio = async (
  base64Audio: string, 
  mimeType: string,
  options: ProcessingOptions
): Promise<{chunks: SubtitleChunk[], kit: SocialMediaKit}> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Transcribe and analyze this audio for Social Media. 
  Target Language: ${options.targetLanguage}
  Dialect: ${options.dialect || 'As spoken'}
  WPL: ${options.wordCount}
  English Preference: ${options.englishFormat}
  Output JSON containing transcription chunks and a Social Media SEO Kit.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { data: base64Audio, mimeType } },
          { text: prompt }
        ]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            chunks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  start: { type: Type.NUMBER },
                  end: { type: Type.NUMBER },
                  label: { type: Type.STRING, description: "hook, cta, important, value, question, or humor" }
                },
                required: ["text", "start", "end"]
              }
            },
            kit: {
              type: Type.OBJECT,
              properties: {
                caption: { type: Type.STRING },
                hashtags: { type: Type.ARRAY, items: { type: Type.STRING } },
                summary: { type: Type.STRING },
                hooks: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["caption", "hashtags", "summary", "hooks"]
            }
          },
          required: ["chunks", "kit"]
        },
      }
    });

    const data = JSON.parse(response.text || '{}');
    return data;
  } catch (error) {
    console.error("Transcription error:", error);
    throw error;
  }
};

import React from 'react';
import { SubtitleChunk, UILanguage } from '../types';

interface SubtitleListProps {
  chunks: SubtitleChunk[];
  onUpdateChunk: (index: number, updated: Partial<SubtitleChunk>) => void;
  onRemoveChunk: (index: number) => void;
  currentTime: number;
  uiLang: UILanguage;
}

const LABEL_COLORS = {
  hook: 'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  cta: 'bg-rose-500/10 text-rose-500 border-rose-500/20',
  important: 'bg-amber-500/10 text-amber-500 border-amber-500/20',
  value: 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
  question: 'bg-indigo-500/10 text-indigo-500 border-indigo-500/20',
  humor: 'bg-purple-500/10 text-purple-500 border-purple-500/20',
};

const SubtitleList: React.FC<SubtitleListProps> = ({ chunks, onUpdateChunk, onRemoveChunk, currentTime, uiLang }) => {
  const isAr = uiLang === 'ar';

  const getLabelText = (label: string) => {
    if (!isAr) return label.toUpperCase();
    const map: Record<string, string> = {
      hook: 'هوك 🎯',
      cta: 'كول تو أكشن 📣',
      important: 'مهم ⭐',
      value: 'قيمة ✨',
      question: 'سؤال ❓',
      humor: 'دعابة 😂',
    };
    return map[label] || label;
  };

  return (
    <div className="space-y-4 pb-24">
      {chunks.map((chunk, index) => {
        const isActive = currentTime >= chunk.start && currentTime <= chunk.end;

        return (
          <div 
            key={index} 
            className={`group p-4 rounded-2xl border transition-all duration-300 relative ${
              isActive 
                ? 'bg-indigo-600/10 border-indigo-500/50 shadow-lg shadow-indigo-500/5' 
                : 'bg-slate-800/30 border-slate-700/50 hover:border-slate-600'
            }`}
          >
            <div className="flex items-start justify-between mb-3">
              <div className="flex items-center gap-2">
                <span className="text-[10px] font-mono text-slate-500 bg-slate-900/50 px-2 py-1 rounded-md border border-slate-700/50">
                  {chunk.start.toFixed(2)}s
                </span>
                {chunk.label && (
                  <span className={`text-[9px] font-black px-2 py-0.5 rounded-full border uppercase tracking-wider ${LABEL_COLORS[chunk.label]}`}>
                    {getLabelText(chunk.label)}
                  </span>
                )}
              </div>
              <button 
                onClick={() => onRemoveChunk(index)}
                className="opacity-0 group-hover:opacity-100 text-slate-600 hover:text-red-400 transition-opacity p-1"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </button>
            </div>
            <textarea
              value={chunk.text}
              onChange={(e) => onUpdateChunk(index, { text: e.target.value })}
              className={`w-full bg-transparent border-none focus:ring-0 text-md leading-relaxed resize-none p-0 overflow-hidden ${
                chunk.text.match(/[\u0600-\u06FF]/) ? 'font-arabic text-right' : 'font-semibold'
              }`}
              rows={Math.ceil(chunk.text.length / 40) || 1}
              dir="auto"
            />
          </div>
        );
      })}
    </div>
  );
};

