import React, { useState, useRef, useEffect } from 'react';
import JSZip from 'jszip';
import { SubtitleChunk, AppStatus, ProcessingOptions, EnglishFormat, UILanguage, SocialMediaKit } from '../types';
import SubtitleList from './SubtitleList';
import { transcribeAudio } from '../services/geminiService';
import { fileToBase64, generateSRT, downloadFile } from '../utils/helpers';

interface StudioProps {
  initialFile: File | null;
  onReset: () => void;
  options: ProcessingOptions;
  uiLang: UILanguage;
}

const Studio: React.FC<StudioProps> = ({ initialFile, onReset, options, uiLang }) => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [chunks, setChunks] = useState<SubtitleChunk[]>([]);
  const [kit, setKit] = useState<SocialMediaKit | null>(null);
  const [currentTime, setCurrentTime] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'timeline' | 'kit'>('timeline');
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);
  const [mediaUrl, setMediaUrl] = useState<string | null>(null);
  const [isMediaVideo, setIsMediaVideo] = useState(false);

  const isArUI = uiLang === 'ar';
  const t = {
    loading: isArUI ? 'جاري التحليل الذكي...' : 'AI Analyzing Content...',
    loadingSub: isArUI ? 'يتم استخراج النص، التصنيفات، وكتابة الكابشن' : 'Extracting text, labels, and writing caption...',
    tabTimeline: isArUI ? 'الخط الزمني' : 'Timeline',
    tabKit: isArUI ? 'عدة السوشيال ميديا' : 'Social Kit',
    segments: isArUI ? 'جزء' : 'Segments',
    downloadSRT: isArUI ? 'تحميل SRT' : 'Download SRT',
    downloadKit: isArUI ? 'تحميل الكابشن' : 'Download Kit',
    downloadAll: isArUI ? 'تحميل الكل (ZIP)' : 'Download All (ZIP)',
    newProject: isArUI ? 'مشروع جديد' : 'New Project',
    retry: isArUI ? 'إعادة المحاولة' : 'Retry',
    kitCaption: isArUI ? 'كابشن جاهز للنشر (SEO)' : 'Ready-to-Post Caption (SEO)',
    kitSummary: isArUI ? 'ملخص المحتوى' : 'Content Summary',
    kitHooks: isArUI ? 'أهم الهوكس (Hooks)' : 'Top Hooks',
    copy: isArUI ? 'نسخ' : 'Copy',
  };

  useEffect(() => {
    if (initialFile) {
      const url = URL.createObjectURL(initialFile);
      setMediaUrl(url);
      setIsMediaVideo(initialFile.type.startsWith('video/'));
      handleProcessFile(initialFile);
    }
    return () => { if (mediaUrl) URL.revokeObjectURL(mediaUrl); };
  }, [initialFile]);

  const handleProcessFile = async (file: File) => {
    try {
      setStatus(AppStatus.PROCESSING);
      setError(null);
      const base64 = await fileToBase64(file);
      const result = await transcribeAudio(base64, file.type, options);
      setChunks(result.chunks);
      setKit(result.kit);
      setStatus(AppStatus.EDITING);
    } catch (err: any) {
      setError(err.message || "Failed.");
      setStatus(AppStatus.ERROR);
    }
  };

  const downloadZip = async () => {
    if (!kit || !chunks.length) return;
    const zip = new JSZip();
    zip.file("subtitles.srt", generateSRT(chunks));

    let kitContent = `SUBFY SOCIAL MEDIA KIT\n`;
    kitContent += `========================\n\n`;
    kitContent += `CAPTION:\n${kit.caption}\n\n`;
    kitContent += `HASHTAGS:\n${kit.hashtags.join(' ')}\n\n`;
    kitContent += `SUMMARY:\n${kit.summary}\n\n`;
    kitContent += `TOP HOOKS:\n${kit.hooks.map(h => `- ${h}`).join('\n')}\n\n`;
    kitContent += `LABELED SEGMENTS:\n`;
    chunks.forEach(c => {
      if (c.label) kitContent += `[${c.label.toUpperCase()}] ${c.text}\n`;
    });

    zip.file("social_media_kit.txt", kitContent);
    const content = await zip.generateAsync({type:"blob"});
    downloadFile(URL.createObjectURL(content), "subfy_bundle.zip", "application/zip");
  };

  const handleTimeUpdate = (e: React.SyntheticEvent<HTMLMediaElement>) => setCurrentTime(e.currentTarget.currentTime);
  const activeChunk = chunks.find(c => currentTime >= c.start && currentTime <= c.end);

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert(isArUI ? 'تم النسخ!' : 'Copied!');
  };

  return (
    <div className={`max-w-7xl mx-auto px-4 py-8 h-full flex flex-col md:flex-row gap-10 overflow-hidden ${isArUI ? 'font-arabic' : ''}`}>
      {/* Preview Column */}
      <div className="w-full md:w-5/12 lg:w-4/12 flex flex-col space-y-6">
        <div className="relative aspect-[9/16] bg-black rounded-[2.5rem] overflow-hidden shadow-2xl border border-white/5 mx-auto w-full max-w-[320px] md:max-w-none ring-1 ring-slate-800">
          {mediaUrl && (isMediaVideo ? (
            <video ref={videoRef} src={mediaUrl} onTimeUpdate={handleTimeUpdate} controls className="w-full h-full object-contain" />
          ) : (
            <div className="w-full h-full flex flex-col items-center justify-center bg-slate-900">
                <div className="w-20 h-20 bg-indigo-500/10 rounded-full flex items-center justify-center animate-pulse mb-6 ring-1 ring-indigo-500/20">
                   <svg className="w-10 h-10 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" strokeWidth={2}/></svg>
                </div>
                <audio ref={audioRef} src={mediaUrl} onTimeUpdate={handleTimeUpdate} controls className="w-4/5" />
            </div>
          ))}
          <div className="absolute inset-x-0 bottom-24 flex justify-center pointer-events-none px-6">
            {activeChunk && (
              <div className="bg-indigo-600/95 text-white px-4 py-2 rounded-xl shadow-2xl text-center border border-white/20 backdrop-blur-md scale-110">
                <p className={`text-sm md:text-base font-black ${activeChunk.text.match(/[\u0600-\u06FF]/) ? 'font-arabic' : ''}`}>
                  {activeChunk.text}
                </p>
              </div>
            )}
          </div>
        </div>

        <div className="grid grid-cols-2 gap-3">
          <button 
            onClick={() => downloadFile(generateSRT(chunks), "subtitles.srt", "text/plain")}
            className="bg-slate-800 hover:bg-slate-700 text-white py-3 rounded-xl text-xs font-black transition-all border border-slate-700/50"
          >
            {t.downloadSRT}
          </button>
          <button 
            onClick={downloadZip}
            className="bg-indigo-600 hover:bg-indigo-500 text-white py-3 rounded-xl text-xs font-black transition-all shadow-lg shadow-indigo-600/20"
          >
            {t.downloadAll}
          </button>
          <button onClick={onReset} className="col-span-2 text-slate-500 hover:text-white py-1 font-bold text-[10px] uppercase tracking-widest">
            {t.newProject}
          </button>
        </div>
      </div>

      {/* Main Workspace */}
      <div className="w-full md:w-7/12 lg:w-8/12 flex flex-col">
        <div className="glass rounded-[2.5rem] flex flex-col h-[650px] shadow-2xl overflow-hidden">
          {/* Tabs */}
          <div className="px-4 py-3 border-b border-white/5 flex items-center justify-center space-x-2 bg-slate-900/50">
             <button 
               onClick={() => setActiveTab('timeline')}
               className={`px-6 py-2 rounded-xl text-xs font-black transition-all ${activeTab === 'timeline' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
             >
               {t.tabTimeline}
             </button>
             <button 
               onClick={() => setActiveTab('kit')}
               className={`px-6 py-2 rounded-xl text-xs font-black transition-all ${activeTab === 'kit' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
             >
               {t.tabKit}
             </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 scrollbar-hide">
            {status === AppStatus.PROCESSING && (
              <div className="flex flex-col items-center justify-center h-full space-y-6">
                <div className="w-16 h-16 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin"></div>
                <div className="text-center">
                  <p className="text-white text-xl font-black animate-pulse">{t.loading}</p>
                  <p className="text-slate-500 text-sm mt-2">{t.loadingSub}</p>
                </div>
              </div>
            )}

            {error && (
              <div className="h-full flex flex-col items-center justify-center p-8 text-center">
                 <p className="text-white font-black text-lg mb-6">{error}</p>
                 <button onClick={() => initialFile && handleProcessFile(initialFile)} className="bg-red-500 hover:bg-red-400 text-white px-8 py-3 rounded-2xl font-black">{t.retry}</button>
              </div>
            )}

            {status === AppStatus.EDITING && activeTab === 'timeline' && (
              <SubtitleList 
                chunks={chunks} 
                onUpdateChunk={(i, u) => { const n = [...chunks]; n[i] = {...n[i], ...u}; setChunks(n); }} 
                onRemoveChunk={(i) => setChunks(chunks.filter((_, idx) => idx !== i))} 
                currentTime={currentTime}
                uiLang={uiLang}
              />
            )}

            {status === AppStatus.EDITING && activeTab === 'kit' && kit && (
              <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                {/* Caption Section */}
                <div className="space-y-4">
                  <div className="flex items-center justify-between">
                    <h3 className="text-sm font-black text-indigo-400 uppercase tracking-widest">{t.kitCaption}</h3>
                    <button onClick={() => copyToClipboard(`${kit.caption}\n\n${kit.hashtags.join(' ')}`)} className="text-[10px] bg-indigo-500/10 hover:bg-indigo-500/20 px-3 py-1 rounded-full text-indigo-400 font-bold uppercase transition-all">
                      {t.copy}
                    </button>
                  </div>
                  <div className="bg-slate-900/60 p-5 rounded-3xl border border-white/5 text-slate-300 text-sm leading-relaxed whitespace-pre-wrap">
                    {kit.caption}
                    <div className="mt-4 flex flex-wrap gap-2">
                      {kit.hashtags.map((tag, i) => (
                        <span key={i} className="text-indigo-400 font-bold">{tag}</span>
                      ))}
                    </div>
                  </div>
                </div>

                {/* Hooks Section */}
                <div className="space-y-4">
                  <h3 className="text-sm font-black text-rose-400 uppercase tracking-widest">{t.kitHooks}</h3>
                  <div className="grid grid-cols-1 gap-3">
                    {kit.hooks.map((hook, i) => (
                      <div key={i} className="bg-rose-500/5 p-4 rounded-2xl border border-rose-500/10 text-slate-300 text-sm italic flex items-center">
                        <span className="w-1.5 h-1.5 bg-rose-500 rounded-full mr-3 shrink-0"></span>
                        {hook}
                      </div>
                    ))}
                  </div>
                </div>

                {/* Summary Section */}
                <div className="space-y-4">
                  <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">{t.kitSummary}</h3>
                  <div className="bg-slate-800/20 p-5 rounded-3xl border border-white/5 text-slate-400 text-xs leading-relaxed italic">
                    {kit.summary}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

