  URGENT FIX REQUIRED: 
  The timing in previous versions was inaccurate (SRT length exceeded audio length). 
  You MUST use your thinking budget to:
  1. Measure the exact start/end of every word.
  2. Ensure NO subtitles show during pauses or silences.
  3. Verify that the final timestamp matches the actual end of the audio provided.
  4. Cross-reference the audio duration with your generated timestamps to prevent drift.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          { inlineData: { data: base64Audio, mimeType } },
          { text: prompt }
        ]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        // Using maximum thinking budget to simulate deep acoustic analysis for temporal alignment
        thinkingConfig: { thinkingBudget: 32768 }, 
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            chunks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  start: { type: Type.NUMBER },
                  end: { type: Type.NUMBER },
                  label: { type: Type.STRING }
                },
                required: ["text", "start", "end"]
              }
            },
            kit: {
              type: Type.OBJECT,
              properties: {
                caption: { type: Type.STRING },
                hashtags: { type: Type.ARRAY, items: { type: Type.STRING } },
                summary: { type: Type.STRING },
                hooks: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["caption", "hashtags", "summary", "hooks"]
            }
          },
          required: ["chunks", "kit"]
        },
      }
    });

    const text = response.text || '{}';
    const data = JSON.parse(text);

    // Final sanity check: filter out zero-duration chunks or invalid timestamps
    if (data.chunks) {
      data.chunks = data.chunks.filter((c: SubtitleChunk) => c.end > c.start);
    }

